  ('optometrist-moex-03314', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '不具驗光人員資格，擅自執行驗光業務者，處新臺幣三萬元以上十五萬元以下罰鍰。但下列那些情形不', '["符合驗光人員法第56條第1項、第2項規定且曾應驗光師、驗光生特種考試者，在驗光人員法實 行後五年內仍於已登記經營驗光業務之公司從事驗光業務", "視力表量測或護理人員於驗光師指示下為 之", "視光系已畢業三年之實習生在驗光師指導下執行驗光業務", "僅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03315', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光所收取驗光費用，下列何者正確？①應依驗光師進修專長，訂定特別收費項目  ②收費標準由', '["得適時參考驗光所經營成本，合理修訂收費標準", "訂定收費標準 時得參考同地區各機構收費狀況", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03316', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '醫學倫理學的四項基本原則為：①公義  ②不傷害  ③專業  ④守法  ⑤尊重病人自主  ⑥行善', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03317', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '驗光室應有下列那些驗光必要設備？①視力表  ②電腦驗光機或檢影鏡  ③鏡片驗度儀  ④鏡片磨片機 ⑤鏡片試片組或綜合驗度儀  ⑥角膜弧度儀或角膜地圖儀', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03318', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列何者不符合驗光人員法有關驗光所的開業規範？', '["可自訂特殊服務項目與收費標準，並依此進行收費", "不得以不正當方法，招攬業務", "對於因業務而知悉或持有他人秘密，不得無故洩漏", "接受主管機關對其人員、設備、衛生、安全、收費情形、作業等之檢查及資料蒐集"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03319', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列何者可應專門職業及技術人員高等考試驗光人員考試？', '["中華民國國民於驗光人員法公布施行前，曾在醫療機構或眼鏡行從事驗光業務滿三年，並具專科以上 學校畢業資格者", "中華民國國民於驗光人員法公布施行前，曾在醫療機構或眼鏡行從事驗光業務滿六年以上，並參加經 中央主管機關指定相關團體辦理之繼續教育達一百六十小時以上", "中華民國國民經公立或立案之私立專科以上學校或符合教育部採認規定之國外專科以上學校驗光或視 光系、科畢業，並經實習期滿成績及格，領有畢業證書者", "中華民國國民經特種考試取得驗光人員證書，而後受驗光人員法所定廢止驗光人員證書處分，須重新 考試以再次取得證書者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03320', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光所設置標準，下列何者正確？①驗光所其總樓地板面積，不得小於三十平方公尺  ②驗光所應', '["眼鏡公司（商號）內設置之驗光所，不必設驗光室", "眼鏡公 司（商號）內設置之驗光所，不以獨立出入口為限  ⑤驗光室空間之直線距離至少六公尺", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 43, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03321', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '驗光人員執行業務，發現視力不能矯正至正常者，下列何者正確？①教導使用低視力輔助器具  ②轉介至', '["轉介至醫療機構診治", "轉介後醫師開具之照會單或醫囑單應至少保存三年", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 44, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03322', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '驗光所之負責驗光人員因故不能執行業務時，應指定合於規定資格者代理之。下列何者符合代理資格？', '["驗光師執行業務年資二年以上", "驗光師執行業務年資一年以上", "驗光生執行業務年資五年以上", "驗光生執行業務年資四年以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03323', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '驗光人員的業務範圍，下列那些為正確？①六歲以下兒童，從未給眼科醫師檢查過，由家長帶來驗光所', '["六歲以下兒童，持契約合作的醫師證明文件，由家長帶來驗光所要求驗光", "六歲以上十 五歲以下，從未給眼科醫師檢查過，由家長帶來驗光所要求驗光", "六歲以上十五歲以下，持眼科醫師 證明眼睛病變文件，由家長帶來驗光所要求驗光  ⑤六歲以上十五歲以下，持眼科醫師證明非假性近視 文件，來驗光所要求驗光  ⑥十五歲以上，從未給眼科醫師檢查過，自行前來驗光所要求驗光", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 46, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
